"use strict";const t=require("../utils/request.js");exports.getProfile=function(){return t.request({url:"/auth/profile",method:"GET"})},exports.login=function(e){return t.request({url:"/auth/login",method:"POST",data:{account:e.email,password:e.password}})},exports.logout=function(){return t.request({url:"/auth/logout",method:"POST"})},exports.register=function(e){return t.request({url:"/auth/register",method:"POST",data:e})},exports.wechatLogin=function(e){return t.request({url:"/auth/wechat-login",method:"POST",data:e})};
